// Aetherjelly — an ethereal bioluminescent jellyfish, rebuilt for grace.
//
// Design goals (over the old flat-disk version):
//   * A TALL, rounded domed bell — not a squashed disk — built from a
//     stack of ellipsoid "bands" smooth-welded into one smooth cap. The
//     bands are LABELLED so they paint as a vertical cyan->violet gradient,
//     reading like a translucent glowing membrane.
//   * Long, GRACEFULLY FLOWING tentacles: each traces an S-curve as a
//     chain of smooth-blended capsule segments, tapering to a fine point,
//     arrayed radially. They drape and curl instead of standing like sticks.
//   * GLOWING tips: each tentacle ends in a bright accent bead.
//   * Tasteful dot accents (ocelli) ringing the bell crown.
//
// Label survival (sdf.md): smoothUnion does NOT propagate inner labels, so
// each paintable region is its OWN labelled subtree, hard-unioned at the
// very end. Within a region we smooth-blend freely; the seams between
// regions sit where the colors naturally meet on the curved surface.
const { sdf } = api;

// --- Bell: a stack of ellipsoid bands forming a tall rounded dome -----
// Stacking three ellipsoids of decreasing radius up Z and (implicitly)
// overlapping them by >0.5 gives a smooth parabolic dome, taller and
// rounder than a single squashed sphere. Each band is its OWN label so
// paint runs as a vertical gradient.
const skirt = sdf.ellipsoid(12, 12, 5.5).translate(0, 0, 3.0).label('bandLo');
const waist = sdf.ellipsoid(9.5, 9.5, 7.0).translate(0, 0, 7.5).label('bandMid');
const crown = sdf.ellipsoid(6.0, 6.0, 7.5).translate(0, 0, 12.0).label('bandHi');

// --- Ruffled rim: a thin torus tucked under the bell lip --------------
// The characteristic margin of a jelly + a third accent color. Overlaps
// the skirt by >0.5 so it fuses watertight.
const rim = sdf.torus(11.0, 1.3).translate(0, 0, 2.0).label('rim');

// --- Tentacles: an S-curved chain of tapering capsule segments --------
// We trace a graceful hanging curve with a polyline of control points,
// then connect consecutive points with capsules whose radius shrinks
// toward the tip. smoothUnion(k) between segments removes the joints so
// the whole thing reads as one flowing strand. The TOP point overlaps the
// skirt (radius 12 at z=3) so the tentacle fuses into the bell.
function tentacle() {
  // Control points: start under the bell lip, sweep out, then curl back
  // inward and down into a soft S — like a strand drifting in water.
  // A smooth analytic S-curve sampled densely so the capsule chain reads
  // as one continuous flowing strand (no visible joints). x sweeps out then
  // gently back in via two cosine lobes; the radius tapers to a fine point.
  const N = 14;
  const zTop = 2.5, zBot = -30.0;
  const pts = [], radii = [];
  for (let i = 0; i <= N; i++) {
    const t = i / N;                       // 0 at bell, 1 at tip
    const z = zTop + (zBot - zTop) * t;
    // Two-lobe lateral sway: out near the top, tuck in low, flare a touch
    // at the very tip — a graceful drifting S.
    const x = 10.0 + 3.0 * Math.sin(t * Math.PI) - 2.2 * Math.sin(t * Math.PI * 2);
    pts.push([x, 0, z]);
    radii.push(1.7 * Math.pow(1 - t, 0.85) + 0.35);   // smooth taper to ~0.35
  }
  let strand = null;
  for (let i = 0; i < pts.length - 1; i++) {
    const seg = sdf.capsule(pts[i], pts[i + 1], (radii[i] + radii[i + 1]) * 0.5);
    strand = strand ? strand.smoothUnion(seg, 1.4) : seg;
  }
  return strand;
}
const tentacles = tentacle().label('tentacle').polarArray(7, { axis: 'z' });

// --- Glowing tips: bright bead at each tentacle's drooping end ---------
// Overlaps the tentacle end so the union stays watertight.
const oneTip = sdf.sphere(0.9).translate(10.0, 0, -30.0).label('tip');
const tips = oneTip.polarArray(7, { axis: 'z' });

// --- Oral pillar: a short tapered central stalk -----------------------
// A gentle central anchor under the bell so the tentacle ring reads as
// hanging from a body. Smooth-welds up into the skirt.
const foot = sdf.roundedCylinder(2.6, 9, 1.2)
  .taper(0.06, 'z')
  .translate(0, 0, -2.0)
  .label('foot');

// --- Crown ocelli: a ring of tiny luminous beads atop the dome --------
const ocellus = sdf.sphere(0.95).translate(0, 0, 16.0);
const ocelli = ocellus.polarArray(8, { axis: 'z', radius: 4.5 }).label('ocelli');

// --- Final assembly ---------------------------------------------------
// Hard-union all labelled regions into ONE watertight solid. Bands overlap
// each other and the rim/foot/tentacles overlap the skirt, so the result
// is a single component.
const jelly = sdf.union(
  skirt, waist, crown, rim, foot, tentacles, tips, ocelli,
);

return jelly.build({ edgeLength: 0.4 });

